package registry

import (
	"fmt"
	"strings"
)

// PackageType represents the type of a registry package.
type PackageType string

const (
	PackageTypeWorkflow     PackageType = "workflow"
	PackageTypePlugin       PackageType = "plugin"
	PackageTypePersonaPack  PackageType = "persona-pack"
	PackageTypeTemplatePack PackageType = "template-pack"
	PackageTypeResource     PackageType = "resource"
)

// InstallMapping describes a source→target mapping from a plugin package.
// Marketplace installs use these mappings to select cache contents and
// generated adapter sources; only legacy compatibility installs copy them
// directly into a project worktree.
type InstallMapping struct {
	Source string `yaml:"source"`
	Target string `yaml:"target"`
}

// PackageInstall describes the plugin package materialization contract.
type PackageInstall struct {
	Root       *InstallMapping  `yaml:"root,omitempty"`       // package root; registry installs cache this payload, local overlays may link it
	Skills     []InstallMapping `yaml:"skills,omitempty"`     // skill source directories used to generate agent adapter shims
	Scripts    *InstallMapping  `yaml:"scripts,omitempty"`    // scripts/binaries
	Symlinks   []SymlinkMapping `yaml:"symlinks,omitempty"`   // post-install symlinks
	Executable []string         `yaml:"executable,omitempty"` // paths (relative to root) that must be executable
}

// SymlinkMapping describes a symlink to create during installation.
type SymlinkMapping struct {
	Source string `yaml:"source"` // the source path (relative to install root)
	Target string `yaml:"target"` // the target path (where symlink points)
}

// Package describes a single installable package.
type Package struct {
	Name        string         `yaml:"name"`
	Version     string         `yaml:"version"`
	Description string         `yaml:"description"`
	Type        PackageType    `yaml:"type"`
	Source      string         `yaml:"source"`
	APIVersion  string         `yaml:"api_version,omitempty"`
	Install     PackageInstall `yaml:"install"`
	Keywords    []string       `yaml:"keywords,omitempty"`
	// Extra captures top-level keys not recognized by this DDx version so
	// newer manifests can keep their unknown fields in memory without
	// silently dropping them. See SD-018 "Manifest Versioning". Not
	// marshaled via `yaml:"-"` so callers must preserve it explicitly.
	Extra map[string]any `yaml:"-"`
}

// Registry holds the list of known packages.
type Registry struct {
	Packages []Package
}

// BuiltinRegistry returns the built-in registry of known packages.
func BuiltinRegistry() *Registry {
	return &Registry{
		Packages: []Package{
			{
				Name:        "ddx",
				Version:     "0.4.7",
				Description: "DDx default library: prompts, personas, MCP configs, environments, skills",
				Type:        PackageTypePlugin,
				Source:      "https://github.com/DocumentDrivenDX/ddx",
				Install: PackageInstall{
					Root: &InstallMapping{
						Source: "library",
						// Compatibility manifest target. Registry installs
						// cache the payload under XDG and generate shims; they
						// do not copy this tree into the project.
						Target: ".ddx/plugins/ddx",
					},
					Skills: []InstallMapping{
						{Source: "skills/", Target: ".agents/skills/"},
						{Source: "skills/", Target: ".claude/skills/"},
					},
				},
				Keywords: []string{"library", "prompts", "personas", "mcp", "default", "skills"},
			},
			{
				Name:        "helix",
				Version:     "0.3.2",
				Description: "Supervisory autopilot for AI-assisted software delivery",
				Type:        PackageTypeWorkflow,
				Source:      "https://github.com/DocumentDrivenDX/helix",
				Install: PackageInstall{
					Root: &InstallMapping{
						Source: ".",
						// Compatibility manifest target. Marketplace installs
						// cache HELIX under XDG; .ddx/plugins/helix is reserved
						// for an explicit local checkout overlay.
						Target: ".ddx/plugins/helix",
					},
					// Registry installs generate project-local adapter shims
					// from cached skill sources.
					Skills: []InstallMapping{
						{Source: ".agents/skills/", Target: ".agents/skills/"},
						{Source: ".agents/skills/", Target: ".claude/skills/"},
					},
				},
				Keywords: []string{"workflow", "methodology", "ai", "development"},
			},
		},
	}
}

// Find returns the package with the given name, or an error if not found.
func (r *Registry) Find(name string) (*Package, error) {
	for i := range r.Packages {
		if r.Packages[i].Name == name {
			return &r.Packages[i], nil
		}
	}
	return nil, fmt.Errorf("package %q not found in registry", name)
}

// Search returns all packages whose name, description, or keywords contain the query.
func (r *Registry) Search(query string) []Package {
	q := strings.ToLower(query)
	var results []Package
	for _, pkg := range r.Packages {
		if matchesQuery(pkg, q) {
			results = append(results, pkg)
		}
	}
	return results
}

func matchesQuery(pkg Package, query string) bool {
	if strings.Contains(strings.ToLower(pkg.Name), query) {
		return true
	}
	if strings.Contains(strings.ToLower(pkg.Description), query) {
		return true
	}
	if strings.Contains(strings.ToLower(string(pkg.Type)), query) {
		return true
	}
	for _, kw := range pkg.Keywords {
		if strings.Contains(strings.ToLower(kw), query) {
			return true
		}
	}
	return false
}

// IsResourcePath returns true if name looks like a resource path (e.g. "persona/foo").
func IsResourcePath(name string) bool {
	return strings.Contains(name, "/")
}

package registry

import (
	"os"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestBuiltinRegistry(t *testing.T) {
	r := BuiltinRegistry()
	if r == nil {
		t.Fatal("expected non-nil registry")
	}

	pkg, err := r.Find("helix")
	if err != nil {
		t.Fatalf("expected helix package: %v", err)
	}

	if pkg.Name != "helix" {
		t.Errorf("expected name=helix, got %q", pkg.Name)
	}
	if pkg.Type != PackageTypeWorkflow {
		t.Errorf("expected type=workflow, got %q", pkg.Type)
	}
	if pkg.Version == "" {
		t.Error("expected non-empty version")
	}
	if pkg.Description == "" {
		t.Error("expected non-empty description")
	}
	if pkg.Source == "" {
		t.Error("expected non-empty source")
	}
	if pkg.Install.Skills == nil {
		t.Error("expected install.skills to be set")
	}
}

func TestBuiltinRegistry_DDxPackage(t *testing.T) {
	r := BuiltinRegistry()

	pkg, err := r.Find("ddx")
	if err != nil {
		t.Fatalf("expected ddx package: %v", err)
	}

	if pkg.Name != "ddx" {
		t.Errorf("expected name=ddx, got %q", pkg.Name)
	}
	if pkg.Type != PackageTypePlugin {
		t.Errorf("expected type=plugin, got %q", pkg.Type)
	}
	if pkg.Install.Root == nil {
		t.Fatal("expected install.root to be set")
	}
	if pkg.Install.Root.Source != "library" {
		t.Errorf("expected root source=library, got %q", pkg.Install.Root.Source)
	}
	if pkg.Install.Root.Target != ".ddx/plugins/ddx" {
		t.Errorf("expected root target=.ddx/plugins/ddx, got %q", pkg.Install.Root.Target)
	}
	// ddx plugin ships skills to project-local skill dirs only (FEAT-015).
	if len(pkg.Install.Skills) != 2 {
		t.Errorf("expected 2 skill mappings, got %d", len(pkg.Install.Skills))
	}
	for _, sk := range pkg.Install.Skills {
		if sk.Source != "skills/" {
			t.Errorf("expected ddx skill source=skills/, got %q", sk.Source)
		}
		if strings.HasPrefix(sk.Target, "~") {
			t.Errorf("skill target must be project-relative, got %q", sk.Target)
		}
	}
	if pkg.Install.Scripts != nil {
		t.Error("expected no scripts")
	}
}

func TestFind(t *testing.T) {
	r := BuiltinRegistry()

	pkg, err := r.Find("helix")
	if err != nil {
		t.Fatalf("expected to find helix: %v", err)
	}
	if pkg.Name != "helix" {
		t.Errorf("expected helix, got %q", pkg.Name)
	}

	ddxPkg, err := r.Find("ddx")
	if err != nil {
		t.Fatalf("expected to find ddx: %v", err)
	}
	if ddxPkg.Name != "ddx" {
		t.Errorf("expected ddx, got %q", ddxPkg.Name)
	}

	_, err = r.Find("nonexistent-package")
	if err == nil {
		t.Error("expected error for nonexistent package")
	}
	if !strings.Contains(err.Error(), "nonexistent-package") {
		t.Errorf("expected error to mention package name, got: %v", err)
	}
}

func TestSearch(t *testing.T) {
	r := BuiltinRegistry()

	// Match by name
	results := r.Search("helix")
	if len(results) == 0 {
		t.Error("expected results for 'helix' name search")
	}
	found := false
	for _, p := range results {
		if p.Name == "helix" {
			found = true
		}
	}
	if !found {
		t.Error("expected helix in name search results")
	}

	// Match by description
	results = r.Search("workflow")
	if len(results) == 0 {
		t.Error("expected results for 'workflow' description/type search")
	}

	// Match by keyword
	results = r.Search("methodology")
	if len(results) == 0 {
		t.Error("expected results for 'methodology' keyword search")
	}

	// No match
	results = r.Search("zzz-does-not-exist-zzz")
	if len(results) != 0 {
		t.Errorf("expected no results for non-matching query, got %d", len(results))
	}
}

func TestIsResourcePath(t *testing.T) {
	if !IsResourcePath("persona/foo") {
		t.Error("expected persona/foo to be a resource path")
	}
	if !IsResourcePath("template/my-template") {
		t.Error("expected template/my-template to be a resource path")
	}
	if IsResourcePath("helix") {
		t.Error("expected helix to NOT be a resource path")
	}
	if IsResourcePath("some-package") {
		t.Error("expected some-package to NOT be a resource path")
	}
}

func TestExpandHome(t *testing.T) {
	home, err := os.UserHomeDir()
	if err != nil {
		t.Fatalf("cannot get home dir: %v", err)
	}

	// Use concatenation so the tilde path is not a static literal (FEAT-015 grep gate).
	result := ExpandHome("~" + "/.agents/skills/")
	if !strings.HasPrefix(result, home) {
		t.Errorf("expected expanded path to start with %q, got %q", home, result)
	}
	if strings.HasPrefix(result, "~") {
		t.Error("expected ~ to be expanded")
	}

	// Non-~ path should be returned unchanged
	plain := "/absolute/path"
	if ExpandHome(plain) != plain {
		t.Errorf("expected unchanged absolute path, got %q", ExpandHome(plain))
	}

	relative := "relative/path"
	if ExpandHome(relative) != relative {
		t.Errorf("expected unchanged relative path, got %q", ExpandHome(relative))
	}
}

func TestLoadSaveState(t *testing.T) {
	tmpDir := t.TempDir()

	// Override HOME so LoadState/SaveState use our temp dir.
	orig := os.Getenv("HOME")
	t.Setenv("HOME", tmpDir)
	defer func() { _ = os.Setenv("HOME", orig) }()

	entry := InstalledEntry{
		Name:        "helix",
		Version:     "0.1.0",
		Type:        PackageTypeWorkflow,
		Source:      "https://github.com/easel/helix",
		InstalledAt: time.Date(2026, 1, 1, 0, 0, 0, 0, time.UTC),
		Files:       []string{"~" + "/.agents/skills/helix.md"},
	}

	state := &InstalledState{
		Installed: []InstalledEntry{entry},
	}

	if err := SaveState(state); err != nil {
		t.Fatalf("SaveState: %v", err)
	}

	loaded, err := LoadState()
	if err != nil {
		t.Fatalf("LoadState: %v", err)
	}

	if len(loaded.Installed) != 1 {
		t.Fatalf("expected 1 entry, got %d", len(loaded.Installed))
	}

	got := loaded.Installed[0]
	if got.Name != entry.Name {
		t.Errorf("expected name=%q, got %q", entry.Name, got.Name)
	}
	if got.Version != entry.Version {
		t.Errorf("expected version=%q, got %q", entry.Version, got.Version)
	}
	if got.Type != entry.Type {
		t.Errorf("expected type=%q, got %q", entry.Type, got.Type)
	}
	if got.Source != entry.Source {
		t.Errorf("expected source=%q, got %q", entry.Source, got.Source)
	}
	if len(got.Files) != 1 || got.Files[0] != entry.Files[0] {
		t.Errorf("expected files=%v, got %v", entry.Files, got.Files)
	}

	// Verify round-trip of time (truncated to second precision by YAML)
	if got.InstalledAt.IsZero() {
		t.Error("expected non-zero InstalledAt")
	}
}

// Legacy copy-installer invariants:
//   - when the compatibility InstallPackage* helpers are used directly, their
//     copied output stays inside projectRoot
//   - marketplace registry installs do not use this path; they cache payloads
//     under XDG and generate project-local adapter shims
//
// The TestInstallSkills_* tests below replace the legacy TestSymlinkSkills_*
// tests deleted with symlinkSkills/pruneStaleSkillLinks.

func walkAndAssertNoSymlinks(t *testing.T, root, projectRoot string) int {
	t.Helper()

	t.Helper()
	count := 0
	absProject, _ := filepath.Abs(projectRoot)
	require.NoError(t, filepath.Walk(root, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			if os.IsNotExist(err) {
				return nil
			}
			return err
		}
		count++
		if info.Mode()&os.ModeSymlink != 0 {
			t.Errorf("FEAT-015: unexpected symlink at %s", path)
		}
		abs, absErr := filepath.Abs(path)
		require.NoError(t, absErr)
		rel, relErr := filepath.Rel(absProject, abs)
		require.NoError(t, relErr)
		if strings.HasPrefix(rel, "..") {
			t.Errorf("FEAT-015: path %s escapes projectRoot %s", path, absProject)
		}
		return nil
	}))
	return count
}

func TestLegacyInstallPackageCopiesStayInsideProjectRoot(t *testing.T) {
	// The compatibility copy-installer must not write through symlinks or
	// escape projectRoot. Forward marketplace installs are covered by
	// cmd/plugin_materialization_test.go and should not create this layout.
	projectRoot := t.TempDir()

	// Simulate the legacy post-install layout: plugin tree + skill copies as
	// real files.
	pluginTree := filepath.Join(projectRoot, ddxroot.DirName, "plugins", "sample")
	require.NoError(t, os.MkdirAll(filepath.Join(pluginTree, ".agents", "skills", "sample-skill"), 0o755))
	require.NoError(t, os.WriteFile(
		filepath.Join(pluginTree, ".agents", "skills", "sample-skill", "SKILL.md"),
		[]byte("---\nname: sample-skill\ndescription: sample\n---\n"), 0o644))

	for _, dir := range []string{".agents/skills/sample-skill", ".claude/skills/sample-skill"} {
		full := filepath.Join(projectRoot, filepath.FromSlash(dir))
		require.NoError(t, os.MkdirAll(full, 0o755))
		require.NoError(t, os.WriteFile(filepath.Join(full, "SKILL.md"),
			[]byte("real file"), 0o644))
	}

	for _, sub := range []string{".ddx/plugins/sample", ".agents/skills", ".claude/skills"} {
		walkAndAssertNoSymlinks(t, filepath.Join(projectRoot, filepath.FromSlash(sub)), projectRoot)
	}
}

func TestInstall_RejectsHomeRootedManifestTarget(t *testing.T) {
	// InstallPackage must reject a manifest whose Root.Target starts with "~"
	// without writing anything to disk. Uses an unreachable Source so the
	// download path can't accidentally succeed; the validation must short-
	// circuit before the network call.
	t.Setenv("HOME", t.TempDir())
	pkg := &Package{
		Name:    "evil-plugin",
		Version: "1.0.0",
		Type:    PackageTypePlugin,
		Source:  "https://invalid.invalid/should-not-be-fetched",
		Install: PackageInstall{
			Root: &InstallMapping{
				Source: ".",
				Target: "~" + "/.ddx/plugins/evil-plugin",
			},
		},
	}

	_, err := InstallPackage(pkg, t.TempDir())
	require.Error(t, err, "InstallPackage must reject home-rooted Root.Target")
	assert.Contains(t, err.Error(), "FEAT-015")
	assert.Contains(t, err.Error(), "Root.Target must be project-relative")
	assert.Contains(t, err.Error(), "evil-plugin")
}

func TestVerifyFiles_AllMissing(t *testing.T) {
	entry := InstalledEntry{
		Name:  "phantom",
		Files: []string{"/nonexistent/path/a", "/nonexistent/path/b"},
	}
	if entry.VerifyFiles() {
		t.Error("expected VerifyFiles to return false when all files missing")
	}
}

func TestVerifyFiles_NoFiles(t *testing.T) {
	entry := InstalledEntry{Name: "empty"}
	if entry.VerifyFiles() {
		t.Error("expected VerifyFiles to return false when no files recorded")
	}
}

func TestVerifyFiles_SomeExist(t *testing.T) {
	tmpDir := t.TempDir()
	realFile := tmpDir + "/exists.txt"
	_ = os.WriteFile(realFile, []byte("x"), 0644)

	entry := InstalledEntry{
		Name:  "partial",
		Files: []string{"/nonexistent/file", realFile},
	}
	if !entry.VerifyFiles() {
		t.Error("expected VerifyFiles to return true when at least one file exists")
	}
}

// TestUninstall_StaleHomeEntriesAreNoOp verifies that UninstallPackage silently
// succeeds when entry.Files contains ~/... paths that do not exist on disk.
// Pre-migration installs may have recorded home-directory paths; these are
// treated as no-op uninstalls (the file is simply absent, not an error).
func TestUninstall_StaleHomeEntriesAreNoOp(t *testing.T) {
	// Use a temp dir as fake HOME so ~/... paths don't collide with a real home.
	fakeHome := t.TempDir()
	t.Setenv("HOME", fakeHome)

	// Build pre-migration global-install record paths using concatenation
	// so the retired home-directory patterns don't appear as static literals.
	tilde := "~"
	entry := &InstalledEntry{
		Name:    "helix",
		Version: "0.1.0",
		Type:    PackageTypePlugin,
		Source:  "https://github.com/example/helix",
		Files: []string{
			tilde + "/.ddx/plugins/helix",
			tilde + "/.agents/skills/helix-align",
			tilde + "/.claude/skills/helix-align",
		},
	}

	// None of the files exist under fakeHome; UninstallPackage must not error.
	if err := UninstallPackage(entry); err != nil {
		t.Fatalf("UninstallPackage returned error for stale home entries: %v", err)
	}
}

package registry

import (
	"archive/tar"
	"compress/gzip"
	"fmt"
	"io"
	iofs "io/fs"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
)

// InstallPackage downloads the source release tarball and copies declared
// install mappings into projectRoot. It records installed files
// (project-relative when possible) in the returned InstalledEntry.
//
// Compatibility shim: this is the historical entrypoint that downloads from a
// remote tarball. New callers should pick the explicit From* variant that
// matches their source (Remote/Dir/FS). Forward marketplace installs must use
// CachePackageFromRemote plus SyncProjectPlugin so payloads live in the shared
// XDG cache and project worktrees contain only lock metadata and generated
// adapter shims.
func InstallPackage(pkg *Package, projectRoot string) (InstalledEntry, error) {
	return InstallPackageFromRemote(pkg, projectRoot)
}

// InstallPackageFromRemote downloads the source release tarball and installs
// the package via the legacy copy-based core install implementation.
func InstallPackageFromRemote(pkg *Package, projectRoot string) (InstalledEntry, error) {
	entry := InstalledEntry{
		Name:        pkg.Name,
		Version:     pkg.Version,
		Type:        pkg.Type,
		Source:      pkg.Source,
		InstalledAt: time.Now(),
	}

	// FEAT-015 early validation: if the package argument already declares a
	// home-rooted Root.Target, reject it before doing any I/O. The post-
	// manifest check below covers manifest-supplied targets after download.
	if pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
		return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
	}

	tmpDir, err := os.MkdirTemp("", "ddx-install-"+pkg.Name+"-*")
	if err != nil {
		return entry, fmt.Errorf("creating temp dir: %w", err)
	}
	defer func() { _ = os.RemoveAll(tmpDir) }()

	tarballURL := githubTarballURL(pkg.Source, pkg.Version)
	extractedDir, err := downloadAndExtract(tarballURL, tmpDir)
	if err != nil {
		return entry, fmt.Errorf("downloading %s: %w", tarballURL, err)
	}

	return installFromExtractedDir(pkg, extractedDir, projectRoot, entry)
}

// InstallPackageFromFS installs the package from an in-memory or embedded
// filesystem (e.g. //go:embed) rooted at the package directory. The FS is
// materialized into a temporary directory and passed through the legacy
// copy-based core install implementation. Network is not used.
func InstallPackageFromFS(pkg *Package, src iofs.FS, projectRoot string) (InstalledEntry, error) {
	entry := InstalledEntry{
		Name:        pkg.Name,
		Version:     pkg.Version,
		Type:        pkg.Type,
		Source:      pkg.Source,
		InstalledAt: time.Now(),
	}

	if src == nil {
		return entry, fmt.Errorf("InstallPackageFromFS: source fs is nil")
	}

	if pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
		return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
	}

	tmpDir, err := os.MkdirTemp("", "ddx-install-fs-"+pkg.Name+"-*")
	if err != nil {
		return entry, fmt.Errorf("creating temp dir: %w", err)
	}
	defer func() { _ = os.RemoveAll(tmpDir) }()

	if err := MaterializeFS(src, tmpDir); err != nil {
		return entry, fmt.Errorf("materializing embedded package: %w", err)
	}

	return installFromExtractedDir(pkg, tmpDir, projectRoot, entry)
}

// installFromExtractedDir is the legacy copy-based install routine used by the
// Remote and FS compatibility entrypoints. It assumes the package contents are
// already present on disk at sourceDir. Do not use this for marketplace
// registry installs; use cachePackageFromDir + SyncProjectPlugin.
func installFromExtractedDir(pkg *Package, sourceDir, projectRoot string, entry InstalledEntry) (InstalledEntry, error) {
	// Switch into projectRoot so relative install targets resolve against the
	// project, not the caller's cwd. This keeps copyMapping, ExpandHome, and
	// the recorded entry.Files paths project-relative.
	if projectRoot != "" {
		absProject, absErr := filepath.Abs(projectRoot)
		if absErr == nil {
			if origDir, gwdErr := os.Getwd(); gwdErr == nil && origDir != absProject {
				if err := os.Chdir(absProject); err == nil {
					defer func() { _ = os.Chdir(origDir) }()
				}
			}
		}
	}

	if manifestPkg, manifestMissing, manifestIssues, manifestErr := LoadPackageManifestWithFallback(sourceDir, pkg); manifestErr == nil || (os.IsNotExist(manifestErr) && manifestMissing) {
		if manifestPkg != nil {
			pkg = manifestPkg
		}
	} else {
		if len(manifestIssues) > 0 {
			return entry, fmt.Errorf("validating package manifest: %s", JoinValidationIssues(manifestIssues))
		}
		return entry, fmt.Errorf("loading package manifest: %w", manifestErr)
	}

	if pkg.Install.Root == nil {
		pkg.Install.Root = &InstallMapping{
			Source: ".",
			Target: defaultPackageRootTarget(pkg.Name),
		}
	}

	// FEAT-015: plugin install targets must be project-relative. Manifests
	// that try to write into the user's home are rejected so plugins can't
	// pollute global state.
	if strings.HasPrefix(pkg.Install.Root.Target, "~") {
		return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
	}

	if issues := ValidatePackageStructure(sourceDir, pkg); len(issues) > 0 {
		return entry, fmt.Errorf("validating package structure: %s", JoinValidationIssues(issues))
	}

	// Process Root mapping for the legacy copy install path.
	var installedRoot string
	files, err := copyMapping(sourceDir, pkg.Install.Root)
	if err != nil {
		return entry, fmt.Errorf("installing plugin root: %w", err)
	}
	entry.Files = append(entry.Files, files...)
	installedRoot = ExpandHome(pkg.Install.Root.Target)

	// Ensure declared executables have the execute bit set.
	for _, rel := range pkg.Install.Executable {
		p := filepath.Join(installedRoot, filepath.FromSlash(rel))
		if info, err := os.Stat(p); err == nil && !info.IsDir() {
			_ = os.Chmod(p, info.Mode()|0111)
		}
	}

	// Process Skills via the manifest mappings for the legacy copy install
	// path. Forward marketplace installs generate shims from the cache instead.
	if len(pkg.Install.Skills) > 0 {
		written, err := installMappings(sourceDir, pkg.Install.Skills)
		if err != nil {
			return entry, fmt.Errorf("installing skills: %w", err)
		}
		entry.Files = append(entry.Files, written...)
	}

	// Process Scripts mapping — copy the script to the target path.
	// If the target is already a symlink, the developer is managing it
	// themselves (e.g. symlink to their git checkout) — skip with a notice.
	if pkg.Install.Scripts != nil {
		dst := ExpandHome(pkg.Install.Scripts.Target)
		if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
			target, _ := os.Readlink(dst)
			fmt.Fprintf(os.Stderr, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
			entry.Files = append(entry.Files, dst)
		} else {
			srcDir := sourceDir
			if installedRoot != "" {
				srcDir = installedRoot
			}
			files, err := copyMapping(srcDir, pkg.Install.Scripts)
			if err != nil {
				return entry, fmt.Errorf("installing scripts: %w", err)
			}
			entry.Files = append(entry.Files, files...)

			// Ensure the installed script is executable.
			if info, err := os.Stat(dst); err == nil && !info.IsDir() {
				_ = os.Chmod(dst, info.Mode()|0111)
			}
		}
	}

	// Process symlinks.
	for _, sym := range pkg.Install.Symlinks {
		src := ExpandHome(sym.Source)
		dst := ExpandHome(sym.Target)

		// Create parent dir if needed.
		if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
			return entry, fmt.Errorf("creating symlink dir %s: %w", filepath.Dir(dst), err)
		}

		// Remove existing symlink/file if present.
		if _, err := os.Lstat(dst); err == nil {
			if err := os.RemoveAll(dst); err != nil {
				return entry, fmt.Errorf("removing existing %s: %w", dst, err)
			}
		}

		if err := os.Symlink(src, dst); err != nil {
			return entry, fmt.Errorf("creating symlink %s -> %s: %w", dst, src, err)
		}
		entry.Files = append(entry.Files, dst)
	}

	return entry, nil
}

// MaterializeFS writes every regular file in src into destDir, preserving the
// relative path layout. Symlinks in the source FS (uncommon for embed.FS) are
// skipped to keep the cross-platform invariant FEAT-015 relies on.
func MaterializeFS(src iofs.FS, destDir string) error {
	return iofs.WalkDir(src, ".", func(p string, d iofs.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if p == "." {
			return nil
		}
		target := filepath.Join(destDir, filepath.FromSlash(p))
		if d.IsDir() {
			return os.MkdirAll(target, 0o755)
		}
		if d.Type()&os.ModeSymlink != 0 {
			return nil
		}
		if !d.Type().IsRegular() {
			return nil
		}
		data, readErr := iofs.ReadFile(src, p)
		if readErr != nil {
			return readErr
		}
		if err := os.MkdirAll(filepath.Dir(target), 0o755); err != nil {
			return err
		}
		return os.WriteFile(target, data, 0o644)
	})
}

