	"github.com/DocumentDrivenDX/ddx/internal/registry/defaultplugin"
)

func BuiltinDDxCachePath() (string, error) {
	pkg, err := BuiltinRegistry().Find("ddx")
	if err != nil {
		return "", err
	}
	return PluginCacheDir(pkg.Name, pkg.Version), nil
}

func EnsureBuiltinDDxCache(cachePath string, force bool) error {
	if !force && BuiltinDDxCacheReady(cachePath) {
		return nil
	}
	if err := os.RemoveAll(cachePath); err != nil {
		return fmt.Errorf("clear baked-in ddx cache %s: %w", cachePath, err)
	}
	if err := os.MkdirAll(filepath.Dir(cachePath), 0o755); err != nil {
		return fmt.Errorf("create baked-in ddx cache root: %w", err)
	}
	if err := MaterializeFS(defaultplugin.FS(), cachePath); err != nil {
		return fmt.Errorf("materialize baked-in ddx cache: %w", err)
	}
	return nil
}

func BuiltinDDxCacheReady(cachePath string) bool {
	for _, rel := range []string{
		"package.yaml",
		filepath.Join("skills", "ddx", "SKILL.md"),
		filepath.Join("personas", "code-reviewer.md"),
		filepath.Join("prompts", "claude", "CLAUDE.md.template"),
		filepath.Join("templates", "README.md"),
	} {
		info, err := os.Stat(filepath.Join(cachePath, rel))
		if err != nil || info.IsDir() {
			return false
		}
	}
	return true
}

package cmd

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/registry"
)

func resolveCommandLibraryPath(workingDir string) (string, error) {
	if workingDir == "" {
		workingDir = "."
	}
	cfg, err := config.LoadWithWorkingDir(workingDir)
	if err != nil {
		return "", fmt.Errorf("failed to load config: %w", err)
	}
	if cfg.Library != nil {
		if configured := strings.TrimSpace(cfg.Library.Path); configured != "" {
			if filepath.IsAbs(configured) {
				return configured, nil
			}
			return filepath.Join(workingDir, configured), nil
		}
	}
	if legacyPath, ok := existingLegacyProjectLibraryPath(workingDir); ok {
		return legacyPath, nil
	}
	return builtinDDxLibraryPath()
}

func existingLegacyProjectLibraryPath(workingDir string) (string, bool) {
	legacyPath := ddxroot.InTree(workingDir, "plugins", "ddx")
	info, err := os.Stat(legacyPath)
	if err != nil || !info.IsDir() {
		return "", false
	}
	return legacyPath, true
}

func builtinDDxLibraryPath() (string, error) {
	cachePath, err := registry.BuiltinDDxCachePath()
	if err != nil {
		return "", err
	}
	if err := registry.EnsureBuiltinDDxCache(cachePath, false); err != nil {
		return "", err
	}
	return cachePath, nil
}

