func TestInitProject_MaterializesBuiltinAdaptersWithoutPluginPayload(t *testing.T) {
	xdgDir := t.TempDir()
	homeDir := t.TempDir()
	t.Setenv("XDG_DATA_HOME", xdgDir)
	t.Setenv("HOME", homeDir)

	te := NewTestEnvironment(t, WithGitInit(false))
